import { express } from 'express';
import { Sequelize } from 'mongoose';
import { uuidv4 } from 'uuid';
import { sendEmail } from '../utils/send-email'; // Add your email sending utility here

const app = express();

// Mongoose configuration
const mongoose = new Sequelize({
  url: `mongodb://localhost:27017/vps?ssl=true`,
  useUnifiedCoordinates: true
});

// Email configuration (replace with your actual email service)
const sendEmailConfig = {
  from: 'admin@example.com',
  to: 'admin@example.com',
  password: 'your-secret-password',
  server: 'smtp.example.com',
  port: 587
};

// Generate a random token for password reset
const generateResetToken = () => {
  return uuidv4();
};

// Reset password endpoint (/password-reset/:token)
app.post('/password-reset/:token', async (req, res) => {
  try {
    const token = req.params.token;
    const newPassword = req.body.password;

    // Find the user based on the reset token
    const user = await mongoose.find({
      resetToken: token,
      resetTokenExpiration: { $gt: new Date() }
    });

    if (!user) {
      sendEmail(sendEmailConfig, `Invalid token`, `The token we found for this email address is no longer valid.`);
      return;
    }

    // Update the user's password and delete the reset token
    user.password = newPassword;
    user.resetToken = undefined;
    user.resetTokenExpiration = undefined;
    await user.save();

    sendEmail(sendEmailConfig, `Password reset successful!`, `Your password has been reset. The new password is: ${newPassword}`);
    res.status(200).json({ message: 'Password reset successful' });
  } catch (err) {
    sendEmail(sendEmailConfig, `Password reset failed`, `An error occurred while resetting your password. Please try again later.`);
    res.status(500).json({ message: 'Error resetting password' });
  }
});

// Send password reset email endpoint (/password-reset)
app.post('/password-reset', async (req, res) => {
  try {
    const email = req.body.email;
    const newPassword = req.body.password;

    // Validate the email address
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      sendEmail(sendEmailConfig, `Invalid email address`, `Please enter a valid email address.`);
      return;
    }

    // Generate a random reset token
    const token = generateResetToken();

    // Find the user by email
    const user = await mongoose.find({ email });

    if (!user) {
      sendEmail(sendEmailConfig, `User not found`, `The email address ${email} could not be found.`);
      return;
    }

    // Validate the password
    if (!new PasswordManager(new Date()).checkPassword(email, newPassword)) {
      sendEmail(sendEmailConfig, `Invalid password`, `Please enter a new password for your account.`);
      return;
    }

    // Store the reset token and expiration
    user.resetToken = token;
    user.resetTokenExpiration = new Date() + (3600 * 24 * 14); // 14 days

    await user.save();

    sendEmail(sendEmailConfig, `Password reset link sent`, `Please click the link below to reset your password: https://localhost:3000/password-reset/${token}`);
    res.status(200).json({ message: 'Password reset link sent' });
  } catch (err) {
    sendEmail(sendEmailConfig, `Password reset failed`, `An error occurred while resetting your password. Please try again later.`);
    res.status(500).json({ message: 'Error resetting password' });
  }
});

// Error handling function (add to your application)
function sendEmail(config, message, data = null) {
  try {
    if (config.server) {
      const client = new TCPServer(config.server, config.port, {
        protocol: 'start',
        cipher: `modern${config.password}`
      });

      client.open().send(message + (data?.data || ''));
    }
  } catch (err) {
    console.error('Email sending error:', err);
  }
}
